300→        };
301→
302→        # Steam (for Wallpaper Engine assets)
303→        programs.steam.enable = true;
304→
305→        programs.dconf.enable = true;
306→
307→        xdg.portal = {
308→          enable = true;
309→          extraPortals = with pkgs; [
310→            xdg-desktop-portal-gtk
311→          ];
