328→            };
329→          };
330→        };
331→
332→        # WiFi MT7925e fix (disable ASPM)
333→        boot.extraModprobeConfig = ''
334→          options mt7925e disable_aspm=1
335→        '';
336→
337→        # Enable nix-ld for running dynamically linked binaries (CrowdStrike, Kolide, etc.)
338→        programs.nix-ld.enable = true;
339→        programs.nix-ld.libraries = with pkgs; [
