        networking.hostName = "matic";
        networking.networkmanager.enable = true;
        networking.networkmanager.wifi.powersave = true;

        # Enable fish shell
        programs.fish.enable = true;

        # User configuration
        users.users.${username} = {
          isNormalUser = true;
